// Get all CSV items from Parse CSV
const csvItems = $('Parse CSV').all();

// Get already-processed RUCs from DB
const existingItems = $('Get Existing RUCs').all();
const existingRucs = new Set(existingItems.map(i => String(i.json.ruc).trim()));

// Filter: only keep companies NOT yet in DB
const pending = csvItems.filter(item => {
  const ruc = String(item.json.RUC || '').trim();
  return ruc.length > 0 && !existingRucs.has(ruc);
});

const total = csvItems.length;
const already = existingRucs.size;
const remaining = pending.length;

console.log(`📊 Total CSV: ${total} | Ya procesados: ${already} | Pendientes: ${remaining}`);

if (remaining === 0) {
  console.log('✅ All companies already processed!');
  return [];  // Empty array = workflow stops naturally, no items to loop
}

console.log(`🚀 Starting with ${remaining} pending companies...`);
return pending.map(item => ({ json: item.json }));

const item = $input.first();

const ruc = String(item.json.RUC || '').trim();
const razonSocial = String(item.json.RazonSocial || '').trim();
const tipo = String(item.json.Tipo || '').trim();
const actividad = String(item.json.Actividad_CIIU3_Principal || '').trim();
const departamento = String(item.json.Departamento || '').trim();
const nroTrab = parseInt(item.json.NroTrab_num || item.json.NroTrab || '0') || 0;

let tier = 'tier5';
if (nroTrab >= 1000) tier = 'tier1';
else if (nroTrab >= 500) tier = 'tier2';
else if (nroTrab >= 100) tier = 'tier3';
else if (nroTrab >= 50) tier = 'tier4';

return {
  json: {
    ruc,
    razonSocial,
    tipo,
    actividad,
    departamento,
    provincia: item.json.Provincia || null,
    distrito: item.json.Distrito || null,
    nroTrabajadores: nroTrab,
    tier
  }
};

const prep = $('Prepare Data').first().json;
const dp = $input.first().json;
const dpOk = dp.success === true;

// Capture real error details when enrichment fails
let errorMsg = null;
let errorType = dp.errorType || null; // 'not_found' | 'proxy_error' | 'parse_error'
if (!dpOk) {
  const parts = [];
  if (errorType) parts.push(`[${errorType}]`);
  if (dp.errorMessage) parts.push(dp.errorMessage);
  else if (dp.code) parts.push(`[${dp.code}]`);
  if (dp.error) parts.push(dp.error);
  else if (dp.message) parts.push(dp.message);
  else if (dp.statusMessage) parts.push(dp.statusMessage);
  if (dp.statusCode) parts.push(`HTTP ${dp.statusCode}`);
  errorMsg = parts.length > 0 ? parts.join(' ') : 'Unknown error';
  console.log(`❌ ${prep.ruc} | ${prep.razonSocial} | ${errorMsg}`);
}

// Determine scrape_status:
// - 'enriched' when success
// - 'not_found_datosperu' when company doesn't exist on DatosPeru (permanent, no retry)
// - 'failed' for proxy/parse/temporary errors (will be retried)
let scrapeStatus = 'failed';
if (dpOk) {
  scrapeStatus = 'enriched';
} else if (errorType === 'not_found') {
  scrapeStatus = 'not_found_datosperu';
}

const data = {
  name: dpOk ? (dp.nombre || prep.razonSocial) : prep.razonSocial,
  estado: dpOk ? (dp.estado || 'ACTIVO') : 'ACTIVO',
  condicion: 'HABIDO',
  tipo_empresa: dpOk ? (dp.tipo || prep.tipo) : prep.tipo,
  actividad_ciiu: dpOk ? (dp.ciiu || prep.actividad) : prep.actividad,
  sector_economico: dpOk ? (dp.sectorEconomico || null) : null,
  comercio_exterior: dpOk ? (dp.marcaComercioExterior || null) : null,
  direccion: dpOk ? (dp.direccion || null) : null,
  referencia: dpOk ? (dp.referencia || null) : null,
  departamento: dpOk ? (dp.departamento || prep.departamento) : prep.departamento,
  provincia: dpOk ? (dp.provincia || prep.provincia) : prep.provincia,
  distrito: dpOk ? (dp.distrito || prep.distrito) : prep.distrito,
  telefonos: dpOk && dp.telefonos ? dp.telefonos : [],
  website: dpOk ? (dp.web || null) : null,
  description: dpOk ? (dp.descripcion || null) : null,
  logo_url: dpOk ? (dp.logoUrl || null) : null,
  fecha_inicio: dpOk ? (dp.fechaInicio || null) : null,
  fecha_inscripcion: dpOk ? (dp.fechaInscripcion || null) : null,
  proveedor_estado: dpOk ? dp.proveedorEstado : false,
  ejecutivos: dpOk ? (dp.ejecutivos || []) : [],
  establecimientos_anexos: dpOk ? (dp.establecimientosAnexos || []) : [],
  historial_trabajadores: dpOk ? (dp.historialTrabajadores || []) : [],
  historial_condiciones: dpOk ? (dp.historialCondiciones || []) : [],
  historial_direcciones: dpOk ? (dp.historialDirecciones || []) : [],
  nro_trabajadores: prep.nroTrabajadores,
  tier: prep.tier,
  source_url: dpOk ? (dp.sourceUrl || null) : null,
  fields_extracted: dpOk ? dp.fieldsExtracted : 0,
  scrape_duration_ms: dpOk ? dp.durationMs : 0,
  scrape_status: scrapeStatus,
  scrape_error: errorMsg,
  error_type: errorType,
  failed_at: dpOk ? null : new Date().toISOString(),
  scraped_at: new Date().toISOString()
};

return { json: {
  ruc: prep.ruc,
  razon_social: data.name,
  data: data,
  source: 'n8n_datosperu_v6',
  updated_at: new Date().toISOString()
}};
